219: // fingerprint calculates a fingerprint that includes all fields except rule's Version and Update timestamp.
220: func (r ruleWithFolder) Fingerprint() fingerprint {
221: 	rule := r.rule
222: 
223: 	sum := fnv.New64()
224: 
225: 	writeBytes := func(b []byte) {
226: 		_, _ = sum.Write(b)
