237: 	}
238: 	// this temp slice is used to convert ints to bytes.
239: 	tmp := make([]byte, 8)
240: 	writeInt := func(u int64) {
241: 		binary.LittleEndian.PutUint64(tmp, uint64(u))
242: 		writeBytes(tmp)
243: 	}
244: 
245: 	// allocate a slice that will be used for sorting keys, so we allocate it only once
246: 	var keys []string
247: 	maxLen := int(math.Max(math.Max(float64(len(rule.Annotations)), float64(len(rule.Labels))), float64(len(rule.Data))))
248: 	if maxLen > 0 {
249: 		keys = make([]string, maxLen)
250: 	}
251: 
252: 	writeLabels := func(lbls map[string]string) {
253: 		// maps do not guarantee predictable sequence of keys.
254: 		// Therefore, to make hash stable, we need to sort keys
255: 		if len(lbls) == 0 {
256: 			return
257: 		}
258: 		idx := 0
259: 		for labelName := range lbls {
260: 			keys[idx] = labelName
261: 			idx++
262: 		}
263: 		sub := keys[:idx]
264: 		sort.Strings(sub)
265: 		for _, name := range sub {
266: 			writeString(name)
267: 			writeString(lbls[name])
268: 		}
269: 	}
270: 	writeQuery := func() {
271: 		// The order of queries is not important as they represent an expression tree.
272: 		// Therefore, the order of elements should not change the hash. Sort by RefID because it is the unique key.
273: 		for i, q := range rule.Data {
274: 			keys[i] = q.RefID
275: 		}
276: 		sub := keys[:len(rule.Data)]
277: 		sort.Strings(sub)
278: 		for _, id := range sub {
279: 			for _, q := range rule.Data {
280: 				if q.RefID == id {
281: 					writeString(q.RefID)
282: 					writeString(q.DatasourceUID)
283: 					writeString(q.QueryType)
284: 					writeInt(int64(q.RelativeTimeRange.From))
285: 					writeInt(int64(q.RelativeTimeRange.To))
286: 					writeBytes(q.Model)
287: 					break
288: 				}
289: 			}
290: 		}
291: 	}
292: 
