294: 	writeString(rule.UID)
295: 	writeString(rule.Title)
296: 	writeString(rule.NamespaceUID)
297: 	writeString(r.folderTitle)
298: 	writeLabels(rule.Labels)
299: 	writeString(rule.Condition)
300: 	writeQuery()
301: 
302: 	if rule.IsPaused {
