304: 	} else {
305: 		writeInt(0)
306: 	}
307: 
308: 	if rule.NotificationSettings != nil {
309: 		binary.LittleEndian.PutUint64(tmp, uint64(rule.NotificationSettings.Fingerprint(nil)))
